import { JobType } from '@/types';
import {
  AppstoreOutlined,
  BookOutlined,
  FileTextOutlined,
  FolderOutlined,
  GlobalOutlined,
  PictureOutlined,
  ReadOutlined,
} from '@ant-design/icons';
import { Tag } from 'antd';

export const JobTypeTag: React.FC<{ value: JobType }> = ({ value }) => {
  function single(icon: React.ReactNode, name: string) {
    return <Tag icon={icon}>{name}</Tag>;
  }
  function batch(icon1: React.ReactNode, icon2: React.ReactNode, name: string) {
    return (
      <Tag color="cyan" style={{ position: 'relative', paddingLeft: 24 }}>
        <span style={{ position: 'absolute', left: 4, top: 0 }}>{icon1}</span>
        <span style={{ position: 'absolute', left: 6, top: 2 }}>{icon2}</span>
        {name}
      </Tag>
    );
  }

  switch (value) {
    case JobType.NOVEL:
      return single(<BookOutlined />, 'Novel');
    case JobType.NOVEL_BATCH:
      return batch(<BookOutlined />, <BookOutlined />, 'Novels');
    case JobType.NOVEL_TRANSLATION:
      return single(<GlobalOutlined />, 'Translate Novel');
    case JobType.NOVEL_TRANSLATION_BATCH:
      return batch(<BookOutlined />, <GlobalOutlined />, 'Translate Novels');
    case JobType.FULL_NOVEL:
      return single(<ReadOutlined />, 'Full Novel');
    case JobType.FULL_NOVEL_BATCH:
      return batch(<ReadOutlined />, <ReadOutlined />, 'Full Novels');
    case JobType.FULL_NOVEL_TRANSLATION:
      return single(<GlobalOutlined />, 'Translate Full Novel');
    case JobType.FULL_NOVEL_TRANSLATION_BATCH:
      return batch(
        <ReadOutlined />,
        <GlobalOutlined />,
        'Translate Full Novels'
      );
    case JobType.VOLUME:
      return single(<FolderOutlined />, 'Volume');
    case JobType.VOLUME_BATCH:
      return batch(<FolderOutlined />, <FolderOutlined />, 'Volumes');
    case JobType.VOLUME_TRANSLATION:
      return single(<GlobalOutlined />, 'Translate Volume');
    case JobType.VOLUME_TRANSLATION_BATCH:
      return batch(<FolderOutlined />, <GlobalOutlined />, 'Translate Volumes');
    case JobType.CHAPTER:
      return single(<FileTextOutlined />, 'Chapter');
    case JobType.CHAPTER_BATCH:
      return batch(<FileTextOutlined />, <FileTextOutlined />, 'Chapters');
    case JobType.CHAPTER_TRANSLATION:
      return single(<GlobalOutlined />, 'Translate Chapter');
    case JobType.CHAPTER_TRANSLATION_BATCH:
      return batch(
        <FileTextOutlined />,
        <GlobalOutlined />,
        'Translate Chapters'
      );
    case JobType.IMAGE:
      return single(<PictureOutlined />, 'Image');
    case JobType.IMAGE_BATCH:
      return batch(<PictureOutlined />, <PictureOutlined />, 'Images');
    case JobType.ARTIFACT:
      return single(<AppstoreOutlined />, 'Artifact');
    case JobType.ARTIFACT_BATCH:
      return batch(<AppstoreOutlined />, <AppstoreOutlined />, 'Artifacts');
    default:
      return null;
  }
};
